// Processar vendas e montar resumo do dia
const items = $input.first().json.items || [];
const hoje = new Date();
const ontem = new Date(hoje.getTime() - 24 * 60 * 60 * 1000);
const ontemStr = ontem.toLocaleDateString('pt-BR');

// Filtrar apenas vendas de ontem
const vendasOntem = items.filter(item => {
  const dataVenda = new Date(item.purchase?.approved_date || item.purchase?.date || 0);
  return dataVenda.toLocaleDateString('pt-BR') === ontemStr;
});

const totalVendas = vendasOntem.length;
const totalReceita = vendasOntem.reduce((sum, item) => {
  return sum + parseFloat(item.purchase?.price?.value || 27);
}, 0);

// Métodos de pagamento
const metodos = {};
vendasOntem.forEach(item => {
  const tipo = item.purchase?.payment?.type || 'OUTRO';
  metodos[tipo] = (metodos[tipo] || 0) + 1;
});

const metodosStr = Object.entries(metodos)
  .map(([k, v]) => {
    const labels = { 'PIX': 'Pix', 'CREDIT_CARD': 'Cartão', 'BILLET': 'Boleto' };
    return `${labels[k] || k}: ${v}`;
  })
  .join(' · ');

// Emoji baseado no resultado
const emoji = totalVendas === 0 ? '😴' : totalVendas >= 3 ? '🚀' : '📈';

let msg = `${emoji} VENDAS DE ONTEM — Empresa Protegida™\n`;
msg += `📅 ${ontemStr}\n\n`;

if (totalVendas === 0) {
  msg += `Vendas: 0\n`;
  msg += `Receita: R$0,00\n\n`;
  msg += `💡 Campanhas ativas? Verificar criativos.`;
} else {
  msg += `🛒 Vendas: ${totalVendas}\n`;
  msg += `💰 Receita: R$${totalReceita.toFixed(2)}\n`;
  if (metodosStr) msg += `💳 ${metodosStr}\n`;
  msg += `\n🥷 Vai lá e faz!`;
}

return [{ json: { mensagem: msg, total_vendas: totalVendas, receita: totalReceita } }];
